using System;
using System.Threading;
using System.Threading.Tasks;

/// <summary>
/// .NET 8 migration of BackgroundProcessor.
///
/// KEY BREAKING CHANGES:
///
/// 1. Thread.Abort() throws PlatformNotSupportedException in .NET 8.
///    ThreadAbortException no longer exists as a runtime mechanism.
///    → Replace with cooperative cancellation via CancellationToken.
///
/// 2. Thread.ResetAbort() throws PlatformNotSupportedException.
///    → Remove entirely; no equivalent needed with cooperative cancellation.
///
/// 3. Catching ThreadAbortException is pointless — it's never thrown.
///    → Catch OperationCanceledException instead for cancellation flow.
///
/// 4. The volatile bool + Thread.Sleep(2000) + Abort() pattern is fragile.
///    → CancellationTokenSource unblocks waiting operations immediately.
///
/// 5. If GetNextItem() blocks indefinitely (e.g., BlockingCollection.Take),
///    the old code relied on Abort() to force-unblock it. In .NET 8 that
///    call would throw PlatformNotSupportedException — the thread hangs
///    forever. You MUST pass a CancellationToken into blocking calls.
/// </summary>
public class BackgroundProcessor : IDisposable
{
    private Task? _workerTask;
    private CancellationTokenSource? _cts;

    public void Start()
    {
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        // Task.Run uses the thread pool — no need to manage Thread directly.
        // The task is equivalent to IsBackground = true (won't block app exit).
        _workerTask = Task.Run(() => ProcessLoop(token), token);
    }

    private void ProcessLoop(CancellationToken token)
    {
        while (!token.IsCancellationRequested)
        {
            try
            {
                // CRITICAL: pass the token into any blocking call.
                // Without this, cancellation can't interrupt the wait —
                // exactly the deadlock that Thread.Abort() used to "solve."
                var item = GetNextItem(token);
                ProcessItem(item);
            }
            catch (OperationCanceledException) when (token.IsCancellationRequested)
            {
                // Replaces the old ThreadAbortException catch.
                // Unlike ThreadAbortException, this does NOT auto-rethrow,
                // so there's no need for ResetAbort(). The finally block
                // runs normally.
                RollbackCurrentTransaction();
                break; // Exit the loop cleanly
            }
            finally
            {
                FlushBuffers();
            }
        }
    }

    public async Task StopAsync(TimeSpan? timeout = null)
    {
        if (_cts is null || _workerTask is null)
            return;

        timeout ??= TimeSpan.FromSeconds(5);

        // Signal cancellation — this immediately unblocks any call
        // that accepts the token (e.g., Channel.ReadAsync, 
        // BlockingCollection.Take(token), Task.Delay(token)).
        _cts.Cancel();

        // Wait for the task to finish, with a timeout as a safety net.
        // Unlike the old Thread.Sleep(2000), this returns immediately
        // if the task finishes early.
        if (await Task.WhenAny(_workerTask, Task.Delay(timeout.Value)) != _workerTask)
        {
            // Task didn't finish in time. Log a warning — but there's no
            // equivalent of Abort() to force-kill it. This is BY DESIGN:
            // .NET 8 requires cooperative cancellation.
            //
            // If you hit this, the root cause is a blocking call that
            // doesn't accept a CancellationToken. Fix the call site.
            Console.Error.WriteLine(
                "WARNING: BackgroundProcessor did not stop within timeout.");
        }
    }

    // Synchronous Stop() if you can't use async at the call site.
    // Prefer StopAsync when possible.
    public void Stop()
    {
        StopAsync().GetAwaiter().GetResult();
    }

    public void Dispose()
    {
        Stop();
        _cts?.Dispose();
        _workerTask?.Dispose();
    }

    // --- Stubs for compilation ---
    // MIGRATION NOTE: update GetNextItem to accept CancellationToken.
    // Before: private object GetNextItem() => queue.Take();           // blocks forever
    // After:  private object GetNextItem(CancellationToken ct) => queue.Take(ct); // cancellable
    private object GetNextItem(CancellationToken token)
    {
        token.ThrowIfCancellationRequested();
        return new object();
    }

    private void ProcessItem(object item) { }
    private void RollbackCurrentTransaction() { }
    private void FlushBuffers() { }
}

